import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./mentorDashboard.css";

const MentorDashboard = () => {
  const navigate = useNavigate();

  /* ---------- STATE ---------- */
  const [activeTab, setActiveTab] = useState("overview");
  const [mentorData, setMentorData] = useState({});
  const [requests, setRequests] = useState([]);
  const [accepted, setAccepted] = useState([]);
  const [error, setError] = useState("");

  // Form fields
  const [newSpec, setNewSpec] = useState("");
  const [newDay, setNewDay] = useState("");
  const [newStart, setNewStart] = useState("");
  const [newEnd, setNewEnd] = useState("");

  // Auth
  const mentor_id = localStorage.getItem("userId");   // sno from login
  const token = localStorage.getItem("token");

  /* ---------- FETCHERS ---------- */
  const fetchOverview = async () => {
    try {
      const res = await fetch(`http://localhost:5050/api/mentors/overview/${mentor_id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);
      setMentorData(data);
    } catch (e) {
      setError("Failed to load overview");
    }
  };

  const fetchRequests = async () => {
    try {
      const res = await fetch(`http://localhost:5050/api/mentors/requests/${mentor_id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);
      setRequests(data);
    } catch (e) {
      setError("Failed to load requests");
    }
  };

  const fetchAccepted = async () => {
    try {
      const res = await fetch(`http://localhost:5050/api/mentors/accepted/${mentor_id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);
      setAccepted(data);
    } catch (e) {
      setError("Failed to load accepted students");
    }
  };

  useEffect(() => {
    if (!mentor_id || !token) {
      navigate("/login");
      return;
    }
    fetchOverview();
    fetchRequests();
    fetchAccepted();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [mentor_id, token]);

  /* ---------- HANDLERS ---------- */
  const handleLogout = () => {
    localStorage.clear();
    navigate("/login");
  };

  const handleDecision = async (requestId, status) => {
    try {
      await fetch(`http://localhost:5050/api/mentors/requests/update/${requestId}`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({ status }),
      });
      fetchRequests();
      fetchAccepted();
    } catch (e) {
      setError("Failed to update request");
    }
  };

  const handleAddSpec = async () => {
    if (!newSpec.trim()) return;
    try {
      await fetch(`http://localhost:5050/api/mentors/specialization`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({ specialization: newSpec }),
      });
      setNewSpec("");
      fetchOverview();
    } catch (e) {
      setError("Failed to add specialization");
    }
  };

  const handleAddSlot = async () => {
    if (!newDay || !newStart || !newEnd) return;
    try {
      await fetch(`http://localhost:5050/api/mentors/availability`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({ day: newDay, start_time: newStart, end_time: newEnd }),
      });
      setNewDay("");
      setNewStart("");
      setNewEnd("");
      fetchOverview();
    } catch (e) {
      setError("Failed to add slot");
    }
  };

  /* ---------- RENDER ---------- */
  return (
    <div className="mentor-dashboard">
      {/* Header */}
      <div className="dashboard-header">
        <h1>Mentor Dashboard</h1>
        <button className="logout-btn" onClick={handleLogout}>
          Logout
        </button>
      </div>

      {/* Tabs */}
      <div className="mentor-tabs">
        <button
          className={activeTab === "overview" ? "active" : ""}
          onClick={() => setActiveTab("overview")}
        >
          Overview
        </button>
        <button
          className={activeTab === "requests" ? "active" : ""}
          onClick={() => setActiveTab("requests")}
        >
          Requests
        </button>
        <button
          className={activeTab === "accepted" ? "active" : ""}
          onClick={() => setActiveTab("accepted")}
        >
          Accepted Students
        </button>
      </div>

      {error && <p className="error">{error}</p>}

      {/* OVERVIEW */}
      {activeTab === "overview" && (
        <div className="overview-section">
          <h2>Welcome, {mentorData.facultyname ?? "Mentor"}!</h2>

          {/* Specializations */}
          <div className="mentor-card">
            <h3>Specializations</h3>
            <p>{mentorData.specialization || "No specialization listed yet"}</p>
            <div className="add-specialization">
              <input
                type="text"
                placeholder="New specialization"
                value={newSpec}
                onChange={(e) => setNewSpec(e.target.value)}
              />
              <button onClick={handleAddSpec}>Add</button>
            </div>
          </div>

          {/* Slots */}
          <div className="mentor-card">
            <h3>Student Slots</h3>
            <p>
              Accepted: <strong>{mentorData.accepted_students ?? 0}</strong> / 7
            </p>
            <p>
              Remaining: <strong>{mentorData.remaining_slots ?? 0}</strong>
            </p>
          </div>

          {/* Availability */}
          <div className="mentor-card">
            <h3>Availability Slots</h3>
            <table>
              <thead>
                <tr>
                  <th>Day</th>
                  <th>Start</th>
                  <th>End</th>
                  <th>Status</th>
                </tr>
              </thead>
              <tbody>
                {mentorData.availability?.length > 0 ? (
                  mentorData.availability.map((slot) => (
                    <tr key={slot.id}>
                      <td>{slot.day}</td>
                      <td>{slot.start_time}</td>
                      <td>{slot.end_time}</td>
                      <td>{slot.status}</td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan="4">No slots added yet</td>
                  </tr>
                )}
              </tbody>
            </table>

            <div className="add-slot">
              <input type="date" value={newDay} onChange={(e) => setNewDay(e.target.value)} />
              <input type="time" value={newStart} onChange={(e)=> setNewStart(e.target.value)} />
              <input type="time" value={newEnd} onChange={(e) => setNewEnd(e.target.value)} />
              <button onClick={handleAddSlot}>Add Slot</button>
            </div>
          </div>
        </div>
      )}

      {/* REQUESTS */}
      {activeTab === "requests" && (
        <div className="requests-section">
          <h2>Pending Requests</h2>
          {requests.length === 0 ? (
            <p>No pending requests</p>
          ) : (
            requests.map((r) => (
              <div key={r.id} className="request-card">
                <h3>{r.project_title}</h3>
                <p>
                  <strong>Student:</strong> {r.studentname}
                </p>
                <p>
                  <strong>Domain:</strong> {r.domain}
                </p>
                <p>{r.description}</p>
                <div className="request-actions">
                  <button className="accept-btn" onClick={() => handleDecision(r.id, "accepted")}>
                    Accept
                  </button>
                  <button className="reject-btn" onClick={() => handleDecision(r.id, "rejected")}>
                    Reject
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
      )}

      {/* ACCEPTED STUDENTS */}
      {activeTab === "accepted" && (
        <div className="accepted-section">
          <h2>Accepted Students</h2>
          {accepted.length === 0 ? (
            <p>No accepted students yet</p>
          ) : (
            accepted.map((a) => (
              <div key={a.id} className="accepted-card">
                <h3>{a.title}</h3>
                <p>
                  <strong>Student:</strong> {a.studentname}
                </p>
                <p>
                  <strong>Domain:</strong> {a.domain}
                </p>
                <p>
                  <strong>Status:</strong> {a.status}
                </p>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
};

export default MentorDashboard;
